mapper.sql:
WHERE z.is_active = true

    AND z.title ILIKE CONCAT('%', #{criteria.searchTitle}, '%')


    AND (z.title ILIKE CONCAT('%', #{criteria.searchInZine}, '%')
    OR z.description ILIKE CONCAT('%', #{criteria.searchInZine}, '%'))


    AND EXISTS (
    SELECT 1 FROM zine_authors za
    JOIN authors a ON a.id = za.author_id
    WHERE za.zine_id = z.id
    AND a.name ILIKE CONCAT('%', #{criteria.authorName}, '%')
    )


    AND EXISTS (
    SELECT 1 FROM zine_contributors zc
    JOIN contributors c ON c.id = zc.contributor_id
    WHERE zc.zine_id = z.id
    AND c.name ILIKE CONCAT('%', #{criteria.contributor}, '%')
    )


    AND EXISTS (
    SELECT 1 FROM zine_genres zg
    JOIN genres g ON g.id = zg.genre_id
    WHERE zg.zine_id = z.id
    AND g.name ILIKE CONCAT('%', #{criteria.genre}, '%')
    )


    AND z.volume = #{criteria.volume}


    AND z.issue_number = #{criteria.issueNumber}


    AND z.total_pages >= #{criteria.minPages}


    AND z.total_pages <= #{criteria.maxPages}


    AND z.file_size >= #{criteria.minFileSize}


    AND z.file_size <= #{criteria.maxFileSize}


    AND z.publication_year >= #{criteria.publicationYearFrom}


    AND z.publication_year <= #{criteria.publicationYearTo}


    AND z.difficulty_level = #{criteria.difficultyLevel}


    AND z.file_format ILIKE #{criteria.fileFormat}


    AND z.is_featured = #{criteria.isFeatured}


    AND z.language_id = #{criteria.languageId}


    AND z.view_count >= #{criteria.minViewCount}


    AND z.read_count >= #{criteria.minReadCount}

mapper.select:


GROUP BY z.id, l.name, cs.name

    HAVING COALESCE(AVG(zr.rating), 0) >= #{criteria.minRating}

ORDER BY ${sortColumn} ${sortType}
LIMIT #{limit} OFFSET #{offset}

SELECT EXISTS (
SELECT 1 FROM zine_views
WHERE viewer_hash = #{viewerHash} AND action_type = #{actionType}
)

SELECT a.* FROM authors a
JOIN zine_authors za ON za.author_id = a.id
WHERE za.zine_id = #{zineId}

SELECT a.name FROM authors a
JOIN zine_authors za ON za.author_id = a.id
WHERE za.zine_id = #{zineId}

SELECT z.id AS bookId, z.slug AS bookSlug, z.title AS bookTitle, z.cover_image_url AS coverImageUrl, z.category AS genre, COALESCE(AVG(zr.rating), 0) AS averageRating FROM zines z LEFT JOIN zine_ratings zr ON zr.zine_id = z.id WHERE z.is_active = true AND z.id NOT IN ( SELECT DISTINCT zrs.zine_id FROM zine_reading_sessions zrs WHERE zrs.user_id = #{userId} )
AND z.category IN
#{genre}
GROUP BY z.id ORDER BY averageRating DESC, z.view_count DESC LIMIT #{limit}

SELECT EXISTS (
SELECT 1 FROM zine_views
WHERE zine_id = #{zineId}
AND user_id = #{userId}
AND action_type = #{actionType}
)

SELECT COUNT(*)
FROM reading_sessions
WHERE user_id = #{userId}
AND zine_id = #{zineId}
